import React, { useState } from 'react';

import TradeForm from './TradeForm';
import TradeList from './TradeList';

const initialTrades = [
    {id:'1-1-1900-111122223', stock:'MES', method:'Bollinger', quantity:1, profitLoss:1},
    {id:'1-1-1900-111122224', stock:'MES', method:'--S & R--', quantity:1, profitLoss:3}
]

const deleteHandler = () => {
    //filter method
    console.log('Delete Trade')
}

function Trades() {
    const [tradeList, setTradeList] = useState(initialTrades)

    return(
        <div>
            <TradeForm tradeList={tradeList} setTradeList={setTradeList} />
            <TradeList tradeList={tradeList} deleteHandler={deleteHandler} />
        </div>    
    )
}

export default Trades;
